from matplotlib.patches import Rectanglefrom matplotlib.transforms import blended_transform_factoryfrom .utils import *from criresviz.plotting.style import (    ZORDER,    BAR_HEIGHT,    MOLECULE_TEXT_SIZE,    MOLECULE_COLORS,          )'''############################################################################################################################### Functions molecules ################################################################################################################################'''def _draw_molecule_label(ax, molecule, rectangle, y):    transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        ax.text(        rectangle.xy[0] + rectangle._width / 2,        y + 0.02,        str(molecule.name),        ha="center",        va="center",        #transform=transform,        zorder=ZORDER["labels"],        color=MOLECULE_COLORS.get(molecule.name),        fontweight="bold",        fontsize=MOLECULE_TEXT_SIZE,    )##############################################def _draw_molecule(molecule, ax, y=1.05, clip=False):        if not ax.has_data():        xmin, xmax = molecule.wavelength_range        ax.set_xlim(xmin, xmax)        ax.set_yticks([])        xmin, xmax = ax.get_xlim()        transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        regions = molecule.active_regions                rectangle = None        for start, end in regions:            if end < xmin or start > xmax:            continue            start = max(start, xmin)        end   = min(end, xmax)            rectangle = Rectangle(            (start, y),            end - start,            BAR_HEIGHT,            #transform=transform,            facecolor=MOLECULE_COLORS.get(molecule.name, "gray"),            zorder=ZORDER["molecule"],            clip_on=clip,        )                    ax.add_patch(rectangle)                if rectangle is not None:        _draw_molecule_label(ax, molecule, rectangle, y)                return ax